import ArchiveClass from '@u/archiveClass'
import Score from './score'
import Tetris from './tetris'
import Music from './music'
import { TETRISSTATE, GETINFO_EVENT, RECEIVE_INFO_EVENT_MUSIC } from './config'

class Contrl implements ArchiveClass{
    tetris: Tetris
    score: Score
    music: Music
    isLive: boolean = false
    isStop: boolean = false
    dirEL: HTMLElement | null = null
    liveOptEL: HTMLElement | null = null
    pauseEL: HTMLElement | null = null

    constructor() {
        this.tetris = new Tetris()
        this.score = new Score()
        this.music = new Music()
        this.dirEL = document.querySelector('#dirBox')
        this.liveOptEL = document.querySelector('#agin')
        this.pauseEL = document.querySelector('#pause')

        if (this.dirEL) {
            this.dirEL.addEventListener('click', this.clickHandle.bind(this))
        }

        if (this.liveOptEL) {
            this.liveOptEL.addEventListener('click', () => this.start(false))
        }

        if (this.pauseEL) {
            this.pauseEL.addEventListener('click', () => this.togglePause())
        }

        document.addEventListener('keydown', this.keyDownHandle.bind(this))
        this.archiveRestore()
        document.addEventListener(GETINFO_EVENT, this.getInfoHandle.bind(this))
    }

    getInfoHandle(e: any) {
        switch (e.detail) {
            case "isStop":
                const receveInfoEventMusic = new CustomEvent(RECEIVE_INFO_EVENT_MUSIC, {detail: this.isStop})
                document.dispatchEvent(receveInfoEventMusic)
                break;
            default:
                break;
        }
    }

    togglePause() {
        if (!this.isLive) return
        this.isStop = !this.isStop
        if (this.isStop) {
            this.music.bgMusic.pause()
            this.pauseEL.innerText = '继续'
            this.archive()
        } else {
            this.music.bgMusic.play()
            this.pauseEL.innerText = '暂停'
            this.clearArchive()
        }
    }

    start(changePiece = true) {
        if (this.isLive) return
        this.tetris.initBoard()
        this.score.init()
        this.music.init()
        this.isLive = true
        this.isStop = false
        this.liveOptEL.innerText = '暂停'
        this.pauseEL.innerText = '暂停'
        this.tetris.draw()
    }

    archive() {
        this.tetris.archive()
        this.score.archive()
        this.music.archive()
        localStorage.setItem(TETRISSTATE, JSON.stringify({ isArchive: true }))
    }

    clearArchive() {
        localStorage.removeItem(TETRISSTATE)
        this.tetris.clearArchive()
        this.score.clearArchive()
    }

    archiveRestore() {
        try {
            const archiveData: { isArchive: boolean } = JSON.parse(localStorage.getItem(TETRISSTATE)!)
            if (archiveData?.isArchive) {
                this.liveOptEL.innerText = '继续'
                this.isLive = true
                this.isStop = true
                this.tetris.archiveRestore()
                this.score.archiveRestore()
                this.music.archiveRestore()
            }
        } catch (error) {
            console.log('存档异常')
        }
    }

    clickHandle(e: MouseEvent) {
        e.preventDefault()
        e.stopPropagation()
        const target = e.target as HTMLElement
        const inner = target.innerText
        const dirMap: { [key: string]: string } = {
            '←': 'left',
            '→': 'right',
            '↓': 'down',
            '↻': 'rotate',
        }
        if (dirMap[inner]) {
            console.log('方向:', dirMap[inner])
        }
    }

    keyDownHandle(e: KeyboardEvent) {
        if (!this.isLive || this.isStop) return
        const keyMap: { [key: string]: string } = {
            'ArrowLeft': 'left',
            'ArrowRight': 'right',
            'ArrowDown': 'down',
            'ArrowUp': 'rotate',
            ' ': 'pause',
        }
        if (keyMap[e.key]) {
            console.log('按键:', keyMap[e.key])
        }
    }
}

export default Contrl
