export default class Tetris {
    X: number = 0
    Y: number = 0
    board: number[][] = []
    currentPiece: number[][] = []
    nextPiece: number[][] = []
    boardWidth: number = 10
    boardHeight: number = 20
    cellSize: number = 20

    constructor() {
        this.initBoard()
    }

    initBoard() {
        this.board = Array.from({ length: this.boardHeight }, () => 
            Array(this.boardWidth).fill(0)
        )
    }

    draw() {
        const boardEL = document.querySelector('#board')!
        boardEL.innerHTML = ''
        this.board.forEach((row, y) => {
            row.forEach((cell, x) => {
                if (cell) {
                    const cellEL = document.createElement('div')
                    cellEL.style.position = 'absolute'
                    cellEL.style.left = `${x * this.cellSize}px`
                    cellEL.style.top = `${y * this.cellSize}px`
                    cellEL.style.width = `${this.cellSize - 2}px`
                    cellEL.style.height = `${this.cellSize - 2}px`
                    cellEL.style.backgroundColor = this.getColor(cell)
                    cellEL.style.border = '1px solid #333'
                    boardEL.appendChild(cellEL)
                }
            })
        })
    }

    getColor(type: number): string {
        const colors = [
            '#000',
            '#FF0D72',
            '#0DC2FF',
            '#0DFF72',
            '#F538FF',
            '#FF8E0D',
            '#FFE138',
            '#3877FF',
        ]
        return colors[type] || '#000'
    }

    archive() {}
    archiveRestore() {}
    clearArchive() {}
}
